const double = n => n * 2;

const doubleAndAdd = (a, b) => {
  const dA = double(a);
  const dB = double(b);
  return dA + dB;
};

console.log(doubleAndAdd(3, 5)); // 16
console.log(doubleAndAdd(10, 20)); // 60

code_writing_tests.solution:
const double = n => n * 2;
const doubleAndAdd = (a, b) => {
  const dA = double(a);
  const dB = double(b);
  return dA + dB;
};
document.getElementById('result1').textContent = doubleAndAdd(3, 5);

const calcTax = income => income * 0.10;
const calcNet = income => {
  const tax = calcTax(income);
  return income - tax;
};
document.getElementById('result2').textContent = calcNet(1000);

const toCm = inches => inches * 2.54;
const toMeters = inches => {
  const cm = toCm(inches);
  return cm / 100;
};
document.getElementById('result3').textContent = toMeters(70);
